query.sparql:
SELECT ?answer WHERE {
  ?answer wdt:P451 wd:Q4463198.
  ?answer wdt:P451 wd:Q4205826.
}

SELECT ?answer WHERE {
  wd:Q860580 wdt:P112 ?founder. # Tencent's founders
  ?founder wdt:P102 wd:Q19211. # Member of National People's Congress
  ?founder rdfs:label ?answer.
  FILTER(LANG(?answer) = "en").
}

SELECT ?answer WHERE {
  wd:Q550311 wdt:P800 ?answer. # Find representative works of the author
  ?answer schema:description ?description. # Check descriptions of the works
  FILTER(CONTAINS(?description, "middle school student")). # Filter for relevant topic
  FILTER(LANG(?description) = "en"). # Ensure the description is in English
}
